var e=[{id:`L2_1`,type:`dialog`,speaker:`MORS_SHADOW_ARMOR_NULL`,text:{KOREA:`마에스트로…… 정녕 너란 말이냐?`,JPN:`マエストロ……本当に貴様なのか？`,ENG:`Maestra... Could it really be you?`,TWN:`你真的……是指揮家嗎？`},stage:{bg:`GRONIA_STREET`,slots:{L:null,C:{char_id:`MORS_SHADOW_ARMOR_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L3_1`,type:`dialog`,speaker:`MORS_SHADOW_ARMOR_NULL`,text:{KOREA:`지난날에 대한 속죄 따윈 없이! 인간의 허물을 쓰고 숨어 지냈단 말이냐!`,JPN:`過ぎし日への償いすら無く！　人間の皮を被り隠れていたというのか！`,ENG:`No atonement for your sins, instead you’ve been hiding under the guise of a human!`,TWN:`你不但沒有為以前的事贖罪！甚至還偽裝成人的樣子躲起來嗎！`},stage:{bg:`GRONIA_STREET`,slots:{L:null,C:{char_id:`MORS_SHADOW_ARMOR_NULL`,face:`UNIT_IDLE`},R:null}}},{id:`L5_1`,type:`dialog`,speaker:`AGENT_GRONIA_NULL_NULL`,text:{KOREA:`그러니까 몇 번이나 아니라고 했잖아!`,JPN:`だから何度も違うって言ってるでしょう！`,ENG:`I told you no several times!`,TWN:`我不是一直跟你說我不是嗎！`},stage:{bg:`GRONIA_STREET`,slots:{L:null,C:{char_id:`AGENT_GRONIA_NULL_NULL`,face:`UNIT_HATE`},R:null}}},{id:`L6_1`,type:`dialog`,speaker:`AGENT_GRONIA_NULL_NULL`,text:{KOREA:`용병 씨! 뭔가 꿍꿍이를 꾸미고 있는 거 아니었어?!`,JPN:`傭兵さん！　なんか策があるんじゃなかったの！？`,ENG:`Ms. Mercenary! Don’t you have anything else up your sleeve?`,TWN:`傭兵小姐！你不是有在打什麼算盤嗎？`},stage:{bg:`GRONIA_STREET`,slots:{L:null,C:{char_id:`AGENT_GRONIA_NULL_NULL`,face:`UNIT_SERIOUS`},R:null}}},{id:`L10_1`,type:`dialog`,speaker:`GSWORD_ADMIN_NULL_NULL`,text:{KOREA:`그래, 슬슬 끝나지 않았으려나?`,JPN:`そうよ、そろそろできたんじゃないかしら？`,ENG:`It shall be ready soon.`,TWN:`是啊，但好像還需要點時間？`},stage:{bg:`GRONIA_STREET`,slots:{L:{char_id:`AGENT_GRONIA_NULL_NULL`,face:`UNIT_SURPRISE`},C:null,R:{char_id:`GSWORD_ADMIN_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L17_1`,type:`dialog`,speaker:`MONTAGNE_ADMIN_NULL_NPC`,text:{KOREA:`저건…… 알렉스 부전대장인가? 살아 있었어?`,JPN:`あれは……アレックス副戦隊長？　生きていたのか？`,ENG:`Is that... Deputy Commander Alex? She’s still alive?`,TWN:`那是……雅蕾克絲副戰隊長嗎？她還活著？`},stage:{bg:`SKY_SUNSET`,slots:{L:null,C:{char_id:`MONTAGNE_ADMIN_NULL_NPC`,face:`UNIT_IDLE`},R:null}}},{id:`L18_1`,type:`dialog`,speaker:`MONTAGNE_ADMIN_NULL_NPC`,text:{KOREA:`그런데 저 여자가 어째서 마에스트로를……?`,JPN:`ところで、どうしてあの女がマエストロを……？`,ENG:`But why is she protecting Maestra...?`,TWN:`她為什麼跟指揮家……？`},stage:{bg:`SKY_SUNSET`,slots:{L:null,C:{char_id:`MONTAGNE_ADMIN_NULL_NPC`,face:`UNIT_IDLE`},R:null}}},{id:`L19_1`,type:`dialog`,speaker:`MONTAGNE_ADMIN_NULL_NPC`,text:{KOREA:`…….`,JPN:`……`,ENG:`…`,TWN:`……`},stage:{bg:`SKY_SUNSET`,slots:{L:null,C:{char_id:`MONTAGNE_ADMIN_NULL_NPC`,face:`UNIT_IDLE`},R:null}}},{id:`L22_1`,type:`dialog`,speaker:`ROGUE_EXTRA_NULL_NULL`,text:{KOREA:`헤, 헤헤……! 역시 나리네 친구야! 굉장한데!`,JPN:`へ、へへ……！　やっぱり旦那のお仲間だ！　すげぇな！`,ENG:`Heh heh...! That friend of yours truly is amazing!`,TWN:`嘿嘿嘿……！真不愧是姊的朋友！超威的！`},stage:{bg:`SKY_SUNSET`,slots:{L:{char_id:`MONTAGNE_ADMIN_NULL_NPC`,face:`UNIT_IDLE`},C:null,R:{char_id:`ROGUE_EXTRA_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L23_1`,type:`dialog`,speaker:`MONTAGNE_ADMIN_NULL_NPC`,text:{KOREA:`그래. 하지만 어째서인지 반응이 없어.`,JPN:`そうだな。でもなぜか反応がない。`,ENG:`Sure. But there’s still no response.`,TWN:`嗯嗯，不過為什麼沒反應？`},stage:{bg:`SKY_SUNSET`,slots:{L:{char_id:`MONTAGNE_ADMIN_NULL_NPC`,face:`UNIT_IDLE`},C:null,R:{char_id:`ROGUE_EXTRA_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L24_1`,type:`dialog`,speaker:`ROGUE_EXTRA_NULL_NULL`,text:{KOREA:`헤, 헤헤, 반응이 없다니 무슨 소리야?`,JPN:`へ、へへ。反応がないってどういうことだ？`,ENG:`Heh, no response? What do you mean?`,TWN:`嘿嘿嘿，沒反應是什麼意思？`},stage:{bg:`SKY_SUNSET`,slots:{L:{char_id:`MONTAGNE_ADMIN_NULL_NPC`,face:`UNIT_IDLE`},C:null,R:{char_id:`ROGUE_EXTRA_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L25_1`,type:`dialog`,speaker:`ROGUE_EXTRA_NULL_NULL`,text:{KOREA:`아무튼 죽이러 가면 되지? 응? 우리 아빠의 원수……!`,JPN:`とにかく殺しに行きゃいいんだろ？　うん？　おやじの仇を……！`,ENG:`Anyway, we can go kill her now, right? Right? To avenge my father..!`,TWN:`總之就先幹掉她再說吧！怎麼樣？我爸的仇……！`},stage:{bg:`SKY_SUNSET`,slots:{L:{char_id:`MONTAGNE_ADMIN_NULL_NPC`,face:`UNIT_IDLE`},C:null,R:{char_id:`ROGUE_EXTRA_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L26_1`,type:`dialog`,speaker:`MONTAGNE_ADMIN_NULL_NPC`,text:{KOREA:`정신 차려. 복수할 생각은 있는 건가?`,JPN:`しっかりしろ。復讐するつもりはあるのか？`,ENG:`Pull yourself together. Do you really want revenge?`,TWN:`清醒一點，你是真的想報仇嗎？`},stage:{bg:`SKY_SUNSET`,slots:{L:{char_id:`MONTAGNE_ADMIN_NULL_NPC`,face:`UNIT_IDLE`},C:null,R:{char_id:`ROGUE_EXTRA_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L27_1`,type:`dialog`,speaker:`ROGUE_EXTRA_NULL_NULL`,text:{KOREA:`뭐?`,JPN:`は？`,ENG:`What?`,TWN:`什麼？`},stage:{bg:`SKY_SUNSET`,slots:{L:{char_id:`MONTAGNE_ADMIN_NULL_NPC`,face:`UNIT_IDLE`},C:null,R:{char_id:`ROGUE_EXTRA_NULL_NULL`,face:`UNIT_IDLE`}}}},{id:`L29_1`,type:`dialog`,speaker:`MONTAGNE_ADMIN_NULL_NPC`,text:{KOREA:`저 상태로 죽이면 그걸로 끝이야.`,JPN:`あのまま殺せばそれでおしまいだ。`,ENG:`If you kill her, that’s it. It’s over.`,TWN:`就那樣把她殺了未免太便宜她。`},stage:{bg:`SKY_SUNSET`,slots:{L:null,C:{char_id:`MONTAGNE_ADMIN_NULL_NPC`,face:`UNIT_IDLE`},R:null}}}];export{e as default};